import React, { useEffect, useState } from "react";
import axiosInstance from "../lib/instance";
import { useAuth } from "../AuthContext";

function Dashboard() {
  const { user } = useAuth();
  const role = user?.role;

  const [data, setData] = useState(null);
  const [loading, setLoading] = useState(false);

  // ✅ Fetch dashboard data
  const fetchDashboard = async () => {
    setLoading(true);
    try {
      let endpoint = "";

      if (role === "ADMIN") endpoint = "/dashboard/admin";
      if (role === "USER") endpoint = "/dashboard/user";
      if (role === "STOREOWNER") endpoint = "/dashboard/store-owner";

      const res = await axiosInstance.get(endpoint);

      console.log("Dashboard:", res.data);

      if (res?.data?.data) {
        setData(res.data.data);
      }
    } catch (error) {
      console.error("Dashboard error:", error);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    if (role) fetchDashboard();
  }, [role]);

  // 🔹 Reusable Card
  const Card = ({ title, value, icon }) => (
    <div className="bg-white p-5 rounded-2xl shadow hover:shadow-lg transition">
      <div className="flex justify-between items-center">
        <h3 className="text-gray-600 text-sm">{title}</h3>
        <span className="text-2xl">{icon}</span>
      </div>
      <p className="text-2xl font-bold text-indigo-600 mt-2">
        {value}
      </p>
    </div>
  );

  return (
    <div className="p-6 bg-gray-100 min-h-screen">
      <h2 className="text-2xl font-bold mb-6 text-indigo-700">
        Dashboard
      </h2>

      {loading ? (
        <p>Loading...</p>
      ) : (
        <>
          {/* ================= ADMIN ================= */}
          {role === "ADMIN" && data && (
            <div className="grid md:grid-cols-4 gap-6">
              <Card title="Total Users" value={data.totalUsers} icon="👤" />
              <Card title="Total Stores" value={data.totalStores} icon="🏪" />
              <Card title="Total Ratings" value={data.totalRatings} icon="⭐" />
              <Card
                title="Overall Avg Rating"
                value={data.overallRating?.toFixed(1)}
                icon="📊"
              />
            </div>
          )}

          {/* ================= USER ================= */}
          {role === "USER" && data && (
            <>
              <div className="grid md:grid-cols-2 gap-6 mb-6">
                <Card
                  title="Stores Rated"
                  value={data.totalRatedStores}
                  icon="🏪"
                />
                <Card
                  title="Total Ratings Given"
                  value={data.totalRatingsGiven}
                  icon="⭐"
                />
              </div>

              {/* Rated Stores */}
              <div className="bg-white p-5 rounded-2xl shadow">
                <h3 className="font-semibold mb-4">
                  Your Ratings
                </h3>

                {data.ratedStores?.length > 0 ? (
                  data.ratedStores.map((store) => (
                    <div
                      key={store.id}
                      className="flex justify-between border-b py-2"
                    >
                      <span>{store.name}</span>
                      <span className="text-yellow-500">
                        ⭐ {store.rating}
                      </span>
                    </div>
                  ))
                ) : (
                  <p className="text-gray-400">No ratings yet</p>
                )}
              </div>
            </>
          )}

          {/* ================= STORE OWNER ================= */}
          {role === "STOREOWNER" && data && (
            <>
              <div className="grid md:grid-cols-3 gap-6 mb-6">
                <Card
                  title="Your Stores"
                  value={data.totalStores}
                  icon="🏪"
                />
                <Card
                  title="Avg Rating"
                  value={data.avgRating?.toFixed(1)}
                  icon="⭐"
                />
                <Card
                  title="Total Users Rated"
                  value={data.totalUsersRated}
                  icon="👥"
                />
              </div>

              {/* Store List */}
              <div className="bg-white p-5 rounded-2xl shadow">
                <h3 className="font-semibold mb-4">
                  Your Stores Overview
                </h3>

                {data.stores?.map((store) => (
                  <div
                    key={store.id}
                    className="flex justify-between border-b py-2"
                  >
                    <span>{store.name}</span>
                    <span className="text-yellow-500">
                      ⭐ {store.averageRating || 0}
                    </span>
                  </div>
                ))}
              </div>
            </>
          )}
        </>
      )}
    </div>
  );
}

export default Dashboard;
